import React, { Suspense, lazy } from 'react';
import { BrowserRouter, Routes, Route, Navigate, Link } from 'react-router-dom';
import { QueryClient, QueryClientProvider } from '@tanstack/react-query';
import { NotificationDropdown } from '../modules/notifications/components/NotificationDropdown';
import { Spinner } from '../components/ui/Spinner';

// Lazy loaded pages to optimize bundle size
const AdminDashboard = lazy(() => import('../modules/dashboard/pages/AdminDashboard').then(m => ({ default: m.AdminDashboard })));
const EmployeeDashboard = lazy(() => import('../modules/dashboard/pages/EmployeeDashboard').then(m => ({ default: m.EmployeeDashboard })));
const SalaryInfoPage = lazy(() => import('../modules/payroll/pages/SalaryInfo').then(m => ({ default: m.SalaryInfoPage })));
const AnalyticsDashboard = lazy(() => import('../modules/analytics/pages/AnalyticsDashboard').then(m => ({ default: m.AnalyticsDashboard })));

const queryClient = new QueryClient();

// Mock Layout to unblock routing (replaces empty Sidebar/Topbar layouts)
const AppShell = ({ children }: { children: React.ReactNode }) => {
  return (
    <div className="flex h-screen bg-gray-50 dark:bg-gray-900 font-sans text-gray-900 dark:text-gray-100">
      <aside className="w-64 bg-white dark:bg-gray-800 border-r border-gray-200 dark:border-gray-700 flex flex-col">
        <div className="h-16 flex items-center px-6 border-b border-gray-200 dark:border-gray-700">
          <span className="text-lg font-bold text-primary">HRMS <span className="text-sm font-normal text-gray-500">by Member 4</span></span>
        </div>
        <nav className="flex-1 overflow-y-auto py-4">
          <ul className="space-y-1 px-3">
            <li>
              <Link to="/dashboard" className="flex items-center px-3 py-2 text-sm font-medium rounded-md hover:bg-gray-100 dark:hover:bg-gray-700">Dashboard</Link>
            </li>
            <li>
              <Link to="/payroll" className="flex items-center px-3 py-2 text-sm font-medium rounded-md hover:bg-gray-100 dark:hover:bg-gray-700">Payroll</Link>
            </li>
            <li>
              <Link to="/analytics" className="flex items-center px-3 py-2 text-sm font-medium rounded-md hover:bg-gray-100 dark:hover:bg-gray-700">Analytics</Link>
            </li>
          </ul>
        </nav>
      </aside>
      
      <div className="flex-1 flex flex-col overflow-hidden">
        <header className="h-16 bg-white dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700 flex items-center justify-end px-6 shadow-sm z-10">
          <NotificationDropdown />
          <div className="ml-4 w-8 h-8 rounded-full bg-primary/20 flex items-center justify-center font-semibold text-primary border border-primary/30">
            A
          </div>
        </header>
        <main className="flex-1 overflow-y-auto p-6 md:p-8">
          <Suspense fallback={<div className="h-full flex items-center justify-center"><Spinner size="lg" /></div>}>
            {children}
          </Suspense>
        </main>
      </div>
    </div>
  );
};

export const Router = () => {
  return (
    <QueryClientProvider client={queryClient}>
      <BrowserRouter>
        <AppShell>
          <Routes>
            <Route path="/" element={<Navigate to="/dashboard" replace />} />
            
            <Route path="/dashboard" element={
              /* Note: In a real app, role check happens here. Assuming Admin for showcase */
              <AdminDashboard />
            } />
            <Route path="/employee-dashboard" element={<EmployeeDashboard />} />
            <Route path="/payroll" element={<SalaryInfoPage />} />
            <Route path="/analytics" element={<AnalyticsDashboard />} />
          </Routes>
        </AppShell>
      </BrowserRouter>
    </QueryClientProvider>
  );
};

export default Router;
